#include <bits/stdc++.h>
using namespace std;

int t,l,r,k,x;

void solve(int l,int r,int k,int x){
    k--;
    if(k%4==1)
        k=1;
    else if(k%4==2)
        k++;
    else if(k%4==3)
        k=0;
    x^=k;
    if(x==0){
        for(int i=l;i<=r;i++)
            if(i%4==3){
                printf("%d\n",i);
                return;
            }
        puts("-1");
    }else if(x==1){
        for(int i=l;i<=r;i++)
            if(i%4==1){
                printf("%d\n",i);
                return;
            }
        puts("-1");
    }else if(x%4==3){
        x--;
        if(l<=x && x<=r)
            printf("%d\n",x);
        else
            puts("-1");
    }else if(x%4==0){
        if(l<=x && x<=r)
            printf("%d\n",x);
        else
            puts("-1");
    }else
        puts("-1");
}

int main(){
    scanf("%d",&t);
    while(t--){
        scanf("%d%d%d%d",&l,&r,&k,&x);
        solve(l,r,k,x);
    }
    return 0;
}
